 1	import React, { FC } from 'react';
 2	
 3	import ExternalLink from '@kubevirt-utils/components/ExternalLink/ExternalLink';
 4	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { isEmpty } from '@kubevirt-utils/utils/utils';
 7	import { OverviewDetailItem } from '@openshift-console/plugin-shared';
 8	import {
 9	  Alert,
10	  AlertVariant,
11	  DescriptionList,
12	  Divider,
13	  Skeleton,
14	  Split,
15	  SplitItem,
16	} from '@patternfly/react-core';
17	
18	import { SubscriptionKind } from '../../../../../../views/clusteroverview/utils/types';
19	
20	import SourceMissingStatus from './components/SourceMissingStatus';
21	import SubscriptionStatus from './components/SubscriptionStatus';
22	
23	import './general-information.scss';
24	
25	type GeneralInformationProps = {
26	  catalogSourceMissing: boolean;
27	  kubevirtSubscription: SubscriptionKind;
28	  loaded: boolean;
29	  loadErrors: Error[];
30	  operatorLink: string;
31	  updateChannel: string;
32	  version: string;
33	};
34	const GeneralInformation: FC<GeneralInformationProps> = ({
35	  catalogSourceMissing,
36	  kubevirtSubscription,
37	  loaded,
38	  loadErrors,
39	  operatorLink,
40	  updateChannel,
41	  version,
42	}) => {
43	  const { t } = useKubevirtTranslation();
44	
45	  return (
46	    <Split className="general-tab" hasGutter>
47	      <SplitItem>
48	        <OverviewDetailItem isLoading={!loaded} title={t('Installed version')}>
49	          {version}
50	        </OverviewDetailItem>
51	      </SplitItem>
52	      <Divider className="general-tab__divider" orientation={{ default: 'vertical' }} />
53	      <SplitItem>
54	        <OverviewDetailItem isLoading={!loaded} title={t('Update status')}>
55	          {catalogSourceMissing ? (
56	            <SourceMissingStatus />
57	          ) : (
58	            <SubscriptionStatus operatorLink={operatorLink} subscription={kubevirtSubscription} />
59	          )}
60	        </OverviewDetailItem>
61	      </SplitItem>
62	      <Divider orientation={{ default: 'vertical' }} />
63	      <SplitItem>
64	        <DescriptionList className="pf-v6-c-description-list">
65	          <VirtualMachineDescriptionItem
66	            descriptionData={
67	              loaded ? (
68	                <ExternalLink href={operatorLink}>{updateChannel}</ExternalLink>
69	              ) : (
70	                <Skeleton />
71	              )
72	            }
73	            bodyContent={t('The channel to track and receive the updates from.')}
74	            descriptionHeader={t('Channel')}
75	            isPopover
76	          />
77	        </DescriptionList>
78	      </SplitItem>
79	      {!isEmpty(loadErrors) && loaded && (
80	        <Alert
81	          className="live-migration-tab--error"
82	          isInline
83	          title={t('Error')}
84	          variant={AlertVariant.danger}
85	        >
86	          {loadErrors.toString()}
87	        </Alert>
88	      )}
89	    </Split>
90	  );
91	};
92	
93	export default GeneralInformation;

